#include <iostream>

class Account {
    long long balance_;
public:
    explicit Account(long long balance) : balance_(balance >= 0 ? balance : 0) {}
    bool apply(long long amount) { if (amount < 0 && -amount > balance_) return false; balance_ += amount; return true; }
    long long balance() const { return balance_; }
};

int main() {
    long long initial{}, transaction{};
    if (!(std::cin >> initial >> transaction) || initial < 0) return 1;
    Account account(initial);
    if (!account.apply(transaction)) std::cout << "rejected\n";
    else std::cout << account.balance() << '\n';
}
